<script>
    import {
        getShopInfo,
        getMessageList,
        getAppointNoticeList,
        getCouponINfo,
        useCoupon
    } from "../../api/index.js";
    export default {
        data() {
            return {
                value: 0,
                value2: 0,
                showPackage:false,
                sf:false,
                ss:false,
                type: "warning",
                shopInfo: {},
                day_order_count: 0,
                member_count: 0,
                month_order_count: 0,
                show: false,
                cid: "",
                banner:[],
                info:{}
            }
        },
        computed: {
            newMessage() {
                return this.$store.state.newMessage;
            },
        },
        watch: {
            newMessage: {
                handler(nval, oval) {
                    let that = this
                    if (nval) {
                        that.getUnread()
                        console.log("nval", nval)
                    }
                },
                deep: true, // 深度监听
                immediate: true, //立即执行
            }
        },
        created() {
            let that = this
            getShopInfo().then((res) => {
                if (res.code == 200) {
                    that.shopInfo = res.data.shop_info
                    that.day_order_count = res.data.day_order_count
                    that.member_count = res.data.member_count
                    that.month_order_count = res.data.month_order_count
                } else {
                    // uni.showToast({
                    //     title: res.message
                    // })
                }
            })
        },
        onShow() {
            let that = this
            that.getUnread()
            that.getLists()
            let cid = uni.getStorageSync("cid")
            // uni.showToast({
            //     title:"cid"+cid,
            //     icon:"none",
            //     duration:50000
            // })
        },
        methods: {
            toCustomer() {
                uni.navigateTo({
                    url: "../customer/customer"
                })
            },
            toPay(){
              uni.navigateTo({
                  url:"/pages/payment/payment"
              })  
            },
            toaaaa(){
               uni.navigateTo({
                   url:"../pautextr/pautextr"
               }) 
            },
            userCoupon(){
                let that = this
                let data = {}
                data.id = that.info.id
                useCoupon(data).then((res) => {
                    that.show = false
                    if(res.code == 200){
                        uni.showToast({
                            title:res.message,
                            duration:2500
                        })
                    }else{
                        uni.showToast({
                            title:res.message,
                            icon:"none",
                            duration:2500
                        })
                    }
                })
            },
            getLists() {
                let that = this
                getAppointNoticeList(1).then((res) => {
                    if (res.code == 200) {
                        that.value2 = res.data.unread_count
                        console.log("ssss", that.value2)
                    }
                })
            },
            getUnread() {
                let that = this
                let data = {}
                data["type"] = "list"
                data["uid"] = 0
                data["mid"] = 0
                data["timestamp"] = 0
                getMessageList(data).then((res) => {
                    let number = 0
                    if (res.code == 200) {
                        console.log('un', res)
                        res.data.messages.forEach((val, index) => {
                            number += val.unread_num
                        })
                        that.value = number
                    }
                })
            },
            toCoupon() {
                uni.navigateTo({
                    url: "../coupon/coupon"
                })
            },
            scanCode() {
                let that = this
                uni.scanCode({
                    autoDecodeCharset: true,
                    success: function(res) {
                        console.log("code",res)
                        if (res.scanType == 'QR_CODE') {
                            uni.navigateTo({
                                url: "../customer/cards/seal/seal?id=" + resu.id
                            })
                        } else if (res.scanType == "CODE_128") {
                            // console.log("result",res.result)
                            console.log("sssaaa",res.result)
                            let temp = res.result.split("-")
                            console.log(temp)
                            if(temp[0] == 'member_coupon'){
                                getCouponINfo(temp[1]).then((res) => {
                                    console.log("couponinfo",res)
                                    if(res.code == 200){
                                        that.show = true
                                        that.banner = res.data.coupon.images
                                        that.info = res.data.coupon
                                    }
                                })
                            }else{
                                uni.navigateTo({
                                    url: "../customer/cards/intergrate/intergrate?id=" + temp[1]
                                })
                            }
                        }
                    }
                })
                // uni.navigateTo({
                //     url:"../map/map"
                // })
            },
            toApp() {
                uni.navigateTo({
                    url: "../appDownload/appDownload"
                })
            },
            toMessage() {
                uni.navigateTo({
                    url: "../message/message"
                })
            },
            toNotice() {
                uni.navigateTo({
                    url: "../notice/notice"
                })
            },
            toMenu() {
                uni.navigateTo({
                    url: "../menu/menu"
                })
            },
            toAppointmeng() {
                uni.navigateTo({
                    url: "../appointment/appointment"
                })
            },
            toCalendar() {
                uni.navigateTo({
                    url: "../calender/calender"
                })
            },
            logOut() {
                uni.redirectTo({
                    url: "../login/login"
                })
            }
        }
    }
</script>

